/*
 * Verilog Circuit Implementation in C
 * Circuit: F = xy + x'z
 * 
 * This C program implements the same combinational logic
 * that would be described in Verilog using dataflow,
 * gate-level, and behavioral modeling styles
 */

#include <stdio.h>
#include <stdlib.h>

/* Dataflow-style implementation: direct boolean expression */
int simple_circuit_dataflow(int x, int y, int z) {
 /*
 * Equivalent Verilog:
 * assign F = (x & y) | (~x & z);
 */
 int term1 = x & y; // xy
 int not_x = ~x & 1; // x' (ensure single bit)
 int term2 = not_x & z; // x'z
 int F = term1 | term2; // xy + x'z
 return F & 1; // Return single bit
}

/* Gate-level simulation: intermediate wires like Verilog structural model */
int simple_circuit_gatelevel(int x, int y, int z) {
 /*
 * Equivalent Verilog (structural):
 * wire w1, w2, w3;
 * not g1 (w1, x); // w1 = x'
 * and g2 (w2, x, y); // w2 = xy
 * and g3 (w3, w1, z); // w3 = x'z
 * or g4 (F, w2, w3); // F = xy + x'z
 */
 int w1 = ~x & 1; // NOT gate: w1 = x'
 int w2 = x & y; // AND gate: w2 = xy
 int w3 = w1 & z; // AND gate: w3 = x'z
 int F = w2 | w3; // OR gate: F = xy + x'z
 return F & 1;
}

/* Behavioral modeling: using if-else like Verilog always block */
int simple_circuit_behavioral(int x, int y, int z) {
 /*
 * Equivalent Verilog (behavioral):
 * always @(x or y or z) begin
 * F = (x & y) | (~x & z);
 * end
 */
 int F;
 if ((x & y) || ((~x & 1) & z)) {
 F = 1;
 } else {
 F = 0;
 }
 return F;
}

/* Testbench - applies all input combinations */
void testbench() {
 int x, y, z, F;

 printf("============================================================\n");
 printf(" Verilog Circuit Simulation - Testbench in C\n");
 printf(" Circuit: F = xy + x'z\n");
 printf("============================================================\n\n");

 printf("%3s %3s %3s | %3s\n", "x", "y", "z", "F");
 printf("-------------------------\n");

 /* Apply all 8 input combinations (2^3 = 8) */
 for (x = 0; x <= 1; x++) {
 for (y = 0; y <= 1; y++) {
 for (z = 0; z <= 1; z++) {
 F = simple_circuit_dataflow(x, y, z);
 printf("%3d %3d %3d | %3d\n", x, y, z, F);
 }
 }
 }

 printf("-------------------------\n");
 printf("Testbench complete!\n\n");
}

/* Verify all three modeling styles produce same results */
void verify_all_models() {
 int x, y, z;
 int df, gl, bh;
 int all_passed = 1;

 printf("============================================================\n");
 printf(" Verifying All Modeling Styles\n");
 printf("============================================================\n\n");

 for (x = 0; x <= 1; x++) {
 for (y = 0; y <= 1; y++) {
 for (z = 0; z <= 1; z++) {
 df = simple_circuit_dataflow(x, y, z);
 gl = simple_circuit_gatelevel(x, y, z);
 bh = simple_circuit_behavioral(x, y, z);

 printf("x=%d y=%d z=%d -> Dataflow:%d GateLevel:%d Behavioral:%d ", 
 x, y, z, df, gl, bh);

 if (df == gl && gl == bh) {
 printf("[PASS]\n");
 } else {
 printf("[FAIL]\n");
 all_passed = 0;
 }
 }
 }
 }

 printf("\nResult: %s\n", all_passed ? "All models consistent!" : "Models have discrepancies!");
}

int main() {
 testbench();
 verify_all_models();

 return 0;
}

/*
 * Verilog Circuit Simulation in Java
 * Circuit: F = xy + x'z
 * 
 * Demonstrates the same combinational logic described in Verilog
 * with dataflow, gate-level, and behavioral modeling equivalents
 */

public class VerilogCircuit {

 /**
 * Dataflow-style implementation
 * Equivalent Verilog: assign F = (x & y) | (~x & z);
 */
 public static int simpleCircuitDataflow(int x, int y, int z) {
 int term1 = x & y; // xy
 int notX = (~x) & 1; // x' (single bit)
 int term2 = notX & z; // x'z
 int F = term1 | term2; // xy + x'z
 return F & 1;
 }

 /**
 * Gate-level (structural) implementation
 * Uses intermediate wires like Verilog structural modeling
 * wire w1, w2, w3;
 * not g1 (w1, x); // w1 = x'
 * and g2 (w2, x, y); // w2 = xy 
 * and g3 (w3, w1, z); // w3 = x'z
 * or g4 (F, w2, w3); // F = xy + x'z
 */
 public static int simpleCircuitGateLevel(int x, int y, int z) {
 int w1 = (~x) & 1; // NOT gate: w1 = x'
 int w2 = x & y; // AND gate: w2 = xy
 int w3 = w1 & z; // AND gate: w3 = x'z
 int F = w2 | w3; // OR gate: F = xy + x'z
 return F & 1;
 }

 /**
 * Behavioral implementation using conditional logic
 * Equivalent to Verilog always block:
 * always @(x or y or z) begin
 * F = (x & y) | (~x & z);
 * end
 */
 public static int simpleCircuitBehavioral(int x, int y, int z) {
 int F;
 if (((x & y) == 1) || (((~x) & 1 & z) == 1)) {
 F = 1;
 } else {
 F = 0;
 }
 return F;
 }

 /**
 * Testbench - applies all input combinations
 */
 public static void runTestbench() {
 System.out.println("============================================================");
 System.out.println(" Verilog Circuit Simulation - Testbench (Java)");
 System.out.println(" Circuit: F = xy + x'z");
 System.out.println("============================================================\n");

 System.out.println(String.format("%3s %3s %3s | %3s", "x", "y", "z", "F"));
 System.out.println("-------------------------");

 // Apply all 8 input combinations (2^3 = 8)
 for (int x = 0; x <= 1; x++) {
 for (int y = 0; y <= 1; y++) {
 for (int z = 0; z <= 1; z++) {
 int F = simpleCircuitDataflow(x, y, z);
 System.out.println(String.format("%3d %3d %3d | %3d", x, y, z, F));
 }
 }
 }

 System.out.println("-------------------------");
 System.out.println("Testbench complete!\n");
 }

 /**
 * Verify all three modeling styles produce identical results
 */
 public static void verifyModelingStyles() {
 System.out.println("============================================================");
 System.out.println(" Verifying All Modeling Styles (Dataflow, Gate-Level, Behavioral)");
 System.out.println("============================================================\n");

 boolean allPassed = true;

 for (int x = 0; x <= 1; x++) {
 for (int y = 0; y <= 1; y++) {
 for (int z = 0; z <= 1; z++) {
 int dataflow = simpleCircuitDataflow(x, y, z);
 int gateLevel = simpleCircuitGateLevel(x, y, z);
 int behavioral = simpleCircuitBehavioral(x, y, z);

 boolean passed = (dataflow == gateLevel) && (gateLevel == behavioral);
 String status = passed ? "[PASS]" : "[FAIL]";

 if (!passed) {
 allPassed = false;
 }

 System.out.println(String.format(
 "x=%d y=%d z=%d -> Dataflow:%d GateLevel:%d Behavioral:%d %s",
 x, y, z, dataflow, gateLevel, behavioral, status));
 }
 }
 }

 System.out.println("\nResult: " + (allPassed ? "All models consistent!" : "Models have discrepancies!"));
 }

 /**
 * Expected truth table computation for verification
 */
 public static void printTruthTable() {
 System.out.println("\n============================================================");
 System.out.println(" Expected Truth Table for F = xy + x'z");
 System.out.println("============================================================\n");

 System.out.println(String.format("%3s %3s %3s | %3s | %s", 
 "x", "y", "z", "F", "Explanation"));
 System.out.println("-----------------------------------------------");

 // Manual truth table with explanations
 String[][] truthTable = {
 {"0", "0", "0", "0", "xy=0, x'z=0"},
 {"0", "0", "1", "1", "xy=0, x'z=1"},
 {"0", "1", "0", "0", "xy=0, x'z=0"},
 {"0", "1", "1", "1", "xy=0, x'z=1"},
 {"1", "0", "0", "0", "xy=0, x'z=0"},
 {"1", "0", "1", "0", "xy=0, x'z=0"},
 {"1", "1", "0", "1", "xy=1, x'z=0"},
 {"1", "1", "1", "1", "xy=1, x'z=0"}
 };

 for (String[] row : truthTable) {
 System.out.println(String.format("%3s %3s %3s | %3s | %s",
 row[0], row[1], row[2], row[3], row[4]));
 }
 }

 public static void main(String[] args) {
 runTestbench();
 verifyModelingStyles();
 printTruthTable();
 }
}
